package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1, got %d", count)
	}

	// Configure OS-specific ping arguments and average latency regex
	var args []string
	var avgRegex *regexp.Regexp
	switch runtime.GOOS {
	case "linux", "darwin":
		args = []string{"-c", strconv.Itoa(count), host}
		// Regex to extract average from Linux/macOS ping summary line
		avgRegex = regexp.MustCompile(`rtt min/avg/max/mdev = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
		// Regex to extract average from Windows ping summary line
		avgRegex = regexp.MustCompile(`Average = ([\d.]+)ms`)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Execute ping command and capture output
	var stdout bytes.Buffer
	cmd := exec.Command("ping", args...)
	cmd.Stdout = &stdout
	// Ignore run error temporarily - we'll check output for valid results first
	_ = cmd.Run()
	output := stdout.Bytes()

	// Extract average latency using regex
	matches := avgRegex.FindSubmatch(output)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse ping output (no average found):\n%s", string(output))
	}

	// Convert captured average string to float64
	avgStr := string(matches[1])
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency %q: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Check command line arguments
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	// Parse command line arguments
	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid ping count: %q (must be a positive integer)\n", countStr)
		os.Exit(1)
	}

	// Measure latency
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
