package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

var timeRegex = regexp.MustCompile(`time=([\d.]+)`)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "linux", "darwin", "freebsd":
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	var stdout, stderr strings.Builder
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	runErr := cmd.Run()

	matches := timeRegex.FindAllStringSubmatch(stdout.String(), -1)
	if len(matches) == 0 {
		errMsg := "no successful ping responses found"
		if stderr.Len() > 0 {
			errMsg += fmt.Sprintf("; stderr: %s", strings.TrimSpace(stderr.String()))
		}
		if runErr != nil {
			errMsg += fmt.Sprintf("; command error: %v", runErr)
		}
		return 0, errors.New(errMsg)
	}

	var sum float64
	parsedCount := 0
	for _, match := range matches {
		t, err := strconv.ParseFloat(match[1], 64)
		if err != nil {
			continue
		}
		sum += t
		parsedCount++
	}

	if parsedCount == 0 {
		errMsg := "no valid ping times could be parsed"
		if stderr.Len() > 0 {
			errMsg += fmt.Sprintf("; stderr: %s", strings.TrimSpace(stderr.String()))
		}
		if runErr != nil {
			errMsg += fmt.Sprintf("; command error: %v", runErr)
		}
		return 0, errors.New(errMsg)
	}

	return sum / float64(parsedCount), nil
}

func main() {
	host := "google.com"
	count := 3
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Failed to measure latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency to %s after %d pings: %.2f ms\n", host, count, avgLatency)
}

