package main

import (
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1, got %d", count)
	}

	// Build ping command arguments based on OS
	var args []string
	countStr := strconv.Itoa(count)
	if runtime.GOOS == "windows" {
		args = []string{"-n", countStr, host}
	} else {
		args = []string{"-c", countStr, host}
	}

	cmd := exec.Command("ping", args...)
	output, cmdErr := cmd.CombinedOutput()
	outStr := string(output)

	// Parse average latency from output
	var avgMatch []string
	if runtime.GOOS == "windows" {
		// Windows ping output format: "Average = X[.Y] ms"
		reWindows := regexp.MustCompile(`Average\s*=\s*(\d+\.?\d*)\s*ms`)
		avgMatch = reWindows.FindStringSubmatch(outStr)
	} else {
		// Unix-like (Linux/macOS) ping output format: "rtt min/avg/max/mdev = X/Y/Z/W ms"
		reUnix := regexp.MustCompile(`rtt\s+min/avg/max(?:/mdev)?\s*=\s*\d+\.?\d*/(\d+\.?\d*)/`)
		avgMatch = reUnix.FindStringSubmatch(outStr)
	}

	// Check if we found the average latency
	if len(avgMatch) < 2 {
		if cmdErr != nil {
			return 0, fmt.Errorf("ping command failed: %w, output: %s", cmdErr, outStr)
		}
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", outStr)
	}

	// Convert average string to float64
	avgLatency, err := strconv.ParseFloat(avgMatch[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value %q: %w", avgMatch[1], err)
	}

	return avgLatency, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid ping count: %s, must be a positive integer\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

