package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly with separate arguments to avoid shell injection and remove bash dependency
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)

	// Look for the line containing RTT statistics (handle both Linux "rtt" and macOS "round-trip" formats)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Check for relevant prefix and required structure to avoid false positives
		if (strings.Contains(line, "rtt") || strings.Contains(line, "round-trip")) &&
			strings.Contains(line, "=") && strings.Contains(line, "/") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w (output: %q)", cmdErr, outputStr)
		}
		return 0, fmt.Errorf("could not find RTT statistics in ping output (output: %q)", outputStr)
	}

	// Extract average latency with flexible regex (supports Linux and macOS, integer/decimal values)
	// Matches patterns like:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.3/23.4/34.5/4.5 ms
	re := regexp.MustCompile(`(?:rtt|round-trip).*=\s*(\d+(?:\.\d+)?)/(\d+(?:\.\d+)?)/`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 3 {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed and unable to parse stats: %w (output: %q, stats line: %q)", cmdErr, outputStr, statsLine)
		}
		return 0, fmt.Errorf("failed to parse average latency from stats line: %q", statsLine)
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed and unable to convert latency: %w (parse error: %w, output: %q)", cmdErr, err, outputStr)
		}
		return 0, fmt.Errorf("failed to convert average latency %q to float: %w", avgStr, err)
	}

	// Return the average even if ping had non-zero exit code (e.g. partial packet loss)
	return avg, nil
}

