package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w, output: %s", err, string(output))
	}

	lines := strings.Split(string(output), "\n")
	var totalLatency float64
	var successResponses int

	for _, line := range lines {
		trimmedLine := strings.TrimSpace(line)
		if trimmedLine == "" {
			continue
		}

		timeIndex := strings.Index(trimmedLine, "time=")
		if timeIndex == -1 {
			continue
		}

		timeSegment := trimmedLine[timeIndex+5:]
		parts := strings.Fields(timeSegment)
		if len(parts) == 0 {
			continue
		}

		numStr := strings.ReplaceAll(strings.TrimSpace(parts[0]), ",", ".")
		latency, parseErr := strconv.ParseFloat(numStr, 64)
		if parseErr != nil {
			continue
		}

		totalLatency += latency
		successResponses++
	}

	if successResponses == 0 {
		return 0, fmt.Errorf("no valid ping responses found in output: %s", string(output))
	}

	return totalLatency / float64(successResponses), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <ping_count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Printf("Invalid ping count: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

