	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	// Construct the appropriate ping command based on the operating system
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default: // Linux, macOS, BSD, etc.
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Execute the ping command and capture combined stdout/stderr
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w, output: %s", err, string(output))
	}

	// Extract average latency from the command output
	avgStr, err := extractAverageLatency(string(output), runtime.GOOS)
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	// Convert the average string to a float64
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency value: %w", err)
	}

	return avgLatency, nil
}

// extractAverageLatency parses the ping output to find the average latency string
func extractAverageLatency(output, goos string) (string, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		trimmedLine := strings.TrimSpace(line)
		if trimmedLine == "" {
			continue
		}

		switch goos {
		case "windows":
			// Windows ping output has a line like "Average = 123ms"
			if strings.Contains(trimmedLine, "Average") {
				parts := strings.Split(trimmedLine, "=")
				if len(parts) < 2 {
					continue
				}
				avgPart := strings.TrimSpace(parts[1])
				// Remove the "ms" suffix
				return strings.TrimSpace(strings.TrimSuffix(avgPart, "ms")), nil
			}
		default:
			// Linux/macOS ping output has a line like "rtt min/avg/max/mdev = 0.123/0.456/0.789/0.101 ms"
			if strings.Contains(trimmedLine, "rtt") || strings.Contains(trimmedLine, "avg") {
				eqParts := strings.Split(trimmedLine, "=")
				if len(eqParts) < 2 {
					continue
				}
				statsPart := strings.TrimSpace(eqParts[1])
				statValues := strings.Split(statsPart, "/")
				if len(statValues) >= 2 {
					return strings.TrimSpace(statValues[1]), nil
				}
			}
		}
	}
	return "", errors.New("average latency not found in output")
}

func main() {
