package main

import (
	"errors"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outStr := string(output)

	var avg float64
	var parseErr error
	switch runtime.GOOS {
	case "windows":
		avg, parseErr = parseWindowsPingOutput(outStr)
	default:
		avg, parseErr = parseUnixPingOutput(outStr)
	}

	if parseErr == nil {
		return avg, nil
	}

	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, outStr)
	}
	return 0, fmt.Errorf("failed to parse ping output: %w", parseErr)
}

func parseUnixPingOutput(out string) (float64, error) {
	lines := strings.Split(out, "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "avg") && strings.Contains(line, "ms") {
			parts := strings.Split(line, "=")
			if len(parts) < 2 {
				continue
			}
			statsPart := strings.TrimSpace(parts[1])
			stats := strings.Split(statsPart, "/")
			if len(stats) >= 2 {
				avgStr := strings.TrimSpace(stats[1])
				avgStr = strings.TrimSuffix(avgStr, "ms")
				avg, err := strconv.ParseFloat(avgStr, 64)
				if err == nil {
					return avg, nil
				}
			}
		}
	}
	return 0, errors.New("could not find average latency in unix ping output")
}

func parseWindowsPingOutput(out string) (float64, error) {
	lines := strings.Split(out, "\n")
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.Contains(strings.ToLower(line), "average") {
			parts := strings.Split(line, "=")
			for i := len(parts) - 1; i >= 0; i-- {
				avgPart := strings.TrimSpace(parts[i])
				avgStr := strings.TrimSuffix(avgPart, "ms")
				avgStr = strings.TrimSpace(avgStr)
				avg, err := strconv.ParseFloat(avgStr, 64)
				if err == nil {
					return avg, nil
				}
			}
		}
	}
	return 0, errors.New("could not find average latency in Windows ping output")
}

func main() {
	host := "google.com"
	count := 4
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

