fix.generatedCode:
package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping command directly without shell to avoid injection/quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Look for RTT stats line (compatible with Linux and macOS)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		if strings.Contains(trimmed, "min/avg/max") && strings.HasSuffix(trimmed, "ms") {
			statsLine = trimmed
			break
		}
	}

	if statsLine == "" {
		return 0, fmt.Errorf("could not find RTT statistics in ping output (err: %w, output: %q)", err, outputStr)
	}

	// Extract average latency (supports Linux rtt/mdev and macOS round-trip/stddev)
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output (err: %w, output: %q, stats line: %q)", err, outputStr, statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w (stats line: %q)", err, statsLine)
	}

	return avg, nil
}

