// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	// Build ping command arguments based on operating system
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute ping command and capture combined output (stdout + stderr)
	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Parse output to extract average latency
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		// Windows ping output format: "Average = Xms"
		avgMarker := "Average = "
		avgIndex := strings.Index(outputStr, avgMarker)
		if avgIndex == -1 {
			if err != nil {
				return 0, fmt.Errorf("ping command failed: %w, output: %s", err, outputStr)
			}
			return 0, fmt.Errorf("could not find average latency in output: %s", outputStr)
		}
		avgPart := outputStr[avgIndex+len(avgMarker):]
		msIndex := strings.Index(avgPart, "ms")
		if msIndex == -1 {
			return 0, fmt.Errorf("could not parse average value from: %s", avgPart)
		}
		avgStr = strings.TrimSpace(avgPart[:msIndex])
	default:
		// Unix-like (Linux/macOS) ping output format: "rtt min/avg/max/mdev = 1.23/4.56/7.89/0.12 ms"
		avgMarker := "avg/"
		avgIndex := strings.Index(outputStr, avgMarker)
		if avgIndex == -1 {
			if err != nil {
				return 0, fmt.Errorf("ping command failed: %w, output: %s", err, outputStr)
			}
			return 0, fmt.Errorf("could not find average latency in output: %s", outputStr)
		}
		avgPart := outputStr[avgIndex+len(avgMarker):]
		slashIndex := strings.Index(avgPart, "/")
		if slashIndex == -1 {
			return 0, fmt.Errorf("could not parse average value from: %s", avgPart)
		}
		avgStr = strings.TrimSpace(avgPart[:slashIndex])
	}

	// Convert average string to float64
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency '%s': %w", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Check command line arguments
	if len(os.Args) < 2 {
		fmt.Printf("Usage: %s <host> [count]\n", os.Args[0])
		fmt.Println("  host: Target host to ping")
		fmt.Println("  count: Number of ping attempts (default: 4)")
		os.Exit(1)
	}

	host := os.Args[1]
	count := 4 // Default ping count

	// Parse optional count argument
	if len(os.Args) >= 3 {
		var err error
		count, err = strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Printf("Error: Invalid count value '%s' - must be a positive integer\n", os.Args[2])
			os.Exit(1)
		}
	}

	// Measure latency
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	// Print result
	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

