package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Run ping directly with arguments to avoid shell injection and unnecessary shell usage
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Look for the line containing RTT statistics, even if the command had an error
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		// If no stats line is found, return an error including command details (if any)
		if err != nil {
			return 0, fmt.Errorf("could not find RTT statistics: ping command failed: %w (output: %q)", err, outputStr)
		}
		return 0, fmt.Errorf("could not find RTT statistics in ping output: %q", outputStr)
	}

	// Extract average latency using a regex that handles both integer and decimal values
	// Example line: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`rtt min/avg/max/mdev = \d+(?:\.\d+)?/(\d+(?:\.\d+)?)/\d+(?:\.\d+)?/\d+(?:\.\d+)? ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from stats line: %q", statsLine)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency %q to float: %w", avgStr, err)
	}

	return avg, nil
}

