package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1, got %d", count)
	}

	// Build ping arguments based on OS
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	// Run command - ignore error initially, check later if no data is found
	_ = cmd.Run()

	// Regex to extract latency values (matches time=12.3 or time<1 format)
	re := regexp.MustCompile(`time[=<]([\d.]+)`)
	matches := re.FindAllStringSubmatch(stdout.String(), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no latency data found: %s", stderr.String())
	}

	var total float64
	successfulParses := 0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		latency, err := strconv.ParseFloat(match[1], 64)
		if err!= nil {
			continue
		}
		total += latency
		successfulParses++
	}

	if successfulParses == 0 {
		return 0, fmt.Errorf("failed to parse valid latency values: %s", stderr.String())
	}

	return total / float64(successfulParses), nil
}

func main() {
	if len(os.Args) < 2 {
		fmt.Printf("Usage: %s <host> [count]\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count := 4 // Default to 4 pings if not specified

	if len(os.Args) >= 3 {
		c, err := strconv.Atoi(os.Args[2])
		if err!= nil || c < 1 {
			fmt.Printf("Invalid count: %s, must be a positive integer\n", os.Args[2])
			os.Exit(1)
		}
		count = c
	}

	avgLatency, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

