package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

var latencyRegex = regexp.MustCompile(`time=([0-9.]+)`)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, cmdErr := cmd.CombinedOutput()
	matches := latencyRegex.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping execution failed: %w, output: %s", cmdErr, string(output))
		}
		return 0, errors.New("no latency data found in ping output")
	}

	sum := 0.0
	parsedCount := 0
	for _, match := range matches {
		if len(match) < 2 {
			continue
		}
		val, err := strconv.ParseFloat(match[1], 64)
		if err == nil {
			sum += val
			parsedCount++
		}
	}

	if parsedCount == 0 {
		return 0, errors.New("failed to parse valid latency values from output")
	}

	return sum / float64(parsedCount), nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err!= nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %q must be a positive integer\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Fprintf(os.Stderr, "Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

