package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// Package-level regex to avoid recompiling on every function call
// Matches both Linux (rtt, mdev) and macOS (round-trip, stddev) ping summary lines
var rttStatsRegex = regexp.MustCompile(`(?:rtt|round-trip).*min/avg/max.*=\s*[\d.]+/([\d.]+)/`)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without a shell to prevent injection attacks and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)

	// Attempt to parse output even if ping returned an error (e.g, partial packet loss may still have valid stats)
	lines := strings.Split(outputStr, "\n")
	var avgStr string
	for _, line := range lines {
		matches := rttStatsRegex.FindStringSubmatch(line)
		if len(matches) >= 2 {
			avgStr = matches[1]
			break
		}
	}

	if avgStr == "" {
		// Return detailed error if we couldn't extract stats
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w (output: %q)", cmdErr, outputStr)
		}
		return 0, fmt.Errorf("could not find RTT statistics in ping output: %q", outputStr)
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to parse average latency value %q: %w", avgStr, err)
	}

	return avg, nil
}

