import (
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

var (
	unixPingRegex    = regexp.MustCompile(`(rtt|round-trip).*=\s*[\d.]+/([\d.]+)/`)
	windowsPingRegex = regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, fmt.Errorf("host cannot be empty")
	}
	if count < 1 {
		return 0, fmt.Errorf("count must be at least 1, received %d", count)
	}

	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)

	var avgStr string
	switch runtime.GOOS {
	case "windows":
		matches := windowsPingRegex.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("parsing Windows ping output failed: %w, output: %q", cmdErr, outputStr)
		}
		avgStr = matches[1]
	default:
		matches := unixPingRegex.FindStringSubmatch(outputStr)
		if len(matches) < 3 {
			return 0, fmt.Errorf("parsing Unix ping output failed: %w, output: %q", cmdErr, outputStr)
		}
		avgStr = matches[2]
	}

	avg, parseErr := strconv.ParseFloat(avgStr, 64)
	if parseErr != nil {
		return 0, fmt.Errorf("parsing average latency %q failed: %w", avgStr, parseErr)
	}

	return avg, nil
}

func main() {
	targetHost := "google.com"
	pingCount := 4

	fmt.Printf("Pinging %s %d times to measure average latency...\n", targetHost, pingCount)
	average, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Average round-trip latency: %.2f ms\n", average)
}

