	"runtime"
	"strconv"
)

var avgLatencyRegex = regexp.MustCompile(`(?:(?:rtt|round-trip)\s+(?:min/avg/max(?:/mdev|/stddev)?)\s*=\s*[\d.]+/([\d.]+)/|Average\s*=\s*([\d.]+)\s*ms)`)

func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	var args []string
	switch runtime.GOOS {
