package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Supports Linux, macOS, and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command arguments based on operating system
	var pingArgs []string
	if runtime.GOOS == "windows" {
		pingArgs = []string{"-n", strconv.Itoa(count), host}
	} else {
		pingArgs = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", pingArgs...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var avgStr string
	var found bool

	if runtime.GOOS == "windows" {
		// Parse Windows ping output - look for "Average = Xms" pattern
		re := regexp.MustCompile(`Average\s*=\s*([\d.]+)ms`)
		for _, line := range lines {
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avgStr = matches[1]
				found = true
				break
			}
		}
	} else {
		// Parse Unix-like (Linux/macOS) ping output
		var statsLine string
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}

		if statsLine == "" {
			return 0, errors.New("could not find RTT statistics in ping output")
		}

		// Split the stats line to extract the RTT values part
		parts := strings.Split(statsLine, " = ")
		if len(parts) < 2 {
			return 0, errors.New("failed to parse RTT statistics line")
		}

		// Get the first field (slash-separated numbers) from the RTT part
		rttFields := strings.Fields(parts[1])
		if len(rttFields) == 0 {
			return 0, errors.New("failed to extract RTT values from statistics line")
		}
		rttNumbers := rttFields[0]

		// Split into min/avg/max/mdev values
		values := strings.Split(rttNumbers, "/")
		if len(values) < 2 {
			return 0, errors.New("failed to extract average latency from RTT values")
		}

		avgStr = values[1]
		found = true
	}

	if !found {
		return 0, errors.New("could not find average latency in ping output")
	}

	// Convert average string to float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

