package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

var (
	unixPingRegex    *regexp.Regexp
	windowsPingRegex *regexp.Regexp
)

func init() {
	// Regex to parse Unix-like (Linux/macOS) ping output, captures the average (second float in min/avg/max)
	unixPingRegex = regexp.MustCompile(`=\s*(\d+\.\d+)/(\d+\.\d+)/`)
	// Regex to parse Windows ping output, captures the Average value
	windowsPingRegex = regexp.MustCompile(`Average\s*=\s*(\d+\.?\d*)`)
}

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// For Linux, macOS, and other Unix-like systems
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture both stdout and stderr to handle all output cases
	output, cmdErr := cmd.CombinedOutput()
	outStr := string(output)

	var avgStr string
	switch runtime.GOOS {
	case "windows":
		matches := windowsPingRegex.FindStringSubmatch(outStr)
		if len(matches) >= 2 {
			avgStr = matches[1]
		}
	default:
		matches := unixPingRegex.FindStringSubmatch(outStr)
		if len(matches) >= 3 {
			avgStr = matches[2] // Second group is the average
		}
	}

	// If we couldn't extract the average, return an error (include command error if present)
	if avgStr == "" {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w, output: %q", cmdErr, outStr)
		}
		return 0, fmt.Errorf("could not parse average latency from ping output: %q", outStr)
	}

	// Convert the average string to a float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to parse average latency value %q: %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err!= nil {
		fmt.Fprintf(os.Stderr, "Invalid ping count: %q must be a positive integer\n", countStr)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

