package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	// Build ping command arguments based on operating system
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute the ping command and capture combined output (stdout + stderr)
	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()

	// Prepare regex pattern to extract average latency based on OS
	var avgRegex *regexp.Regexp
	switch runtime.GOOS {
	case "windows":
		avgRegex = regexp.MustCompile(`Average = (\d+\.?\d*)`)
	default:
		avgRegex = regexp.MustCompile(`(?:rtt|round-trip) (?:min/avg/max/(?:mdev|stddev)) = (\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+)/(\d+\.\d+) ms`)
	}

	// Try to find the average latency in the output
	matches := avgRegex.FindSubmatch(output)
	if matches == nil {
		if err != nil {
			return 0, fmt.Errorf("ping execution failed: %w, output: %s", err, string(output))
		}
		return 0, fmt.Errorf("failed to extract average latency from ping output: %s", string(output))
	}

	// Extract the average value string from the regex matches
	var avgStr string
	switch runtime.GOOS {
	case "windows":
		avgStr = string(matches[1])
	default:
		avgStr = string(matches[2])
	}

	// Convert the average string to a float64
	avg, parseErr := strconv.ParseFloat(avgStr, 64)
	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse average value %q: %w", avgStr, parseErr)
	}

	return avg, nil
}

func main() {
	// Default configuration
	host := "example.com"
	count := 4

	// Parse command line arguments if provided
	if len(os.Args) >= 2 {
		host = os.Args[1]
	}
	if len(os.Args) >= 3 {
		parsedCount, err := strconv.Atoi(os.Args[2])
		if err != nil || parsedCount < 1 {
			fmt.Fprintf(os.Stderr, "Warning: invalid count '%s', using default 4\n", os.Args[2])
		} else {
			count = parsedCount
		}
	}

	// Measure latency and handle results
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	// Print the result
	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avgLatency)
}

