package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Construct ping command with OS-appropriate flags
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		// Unix-like systems (Linux, macOS, BSD, etc.) use -c for count
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	// Try to parse output first, even if ping returned an error (e.g. partial packet loss)
	// First handle Unix-like (Linux/macOS/BSD) output format
	unixPattern := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max(?:/mdev|/stddev)? = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	if matches := unixPattern.FindStringSubmatch(outputStr); len(matches) >= 2 {
		avg, parseErr := strconv.ParseFloat(matches[1], 64)
		if parseErr == nil {
			return avg, nil
		}
	}

	// Handle Windows output format
	windowsPattern := regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
	if matches := windowsPattern.FindStringSubmatch(outputStr); len(matches) >= 2 {
		avg, parseErr := strconv.ParseFloat(matches[1], 64)
		if parseErr == nil {
			return avg, nil
		}
	}

	// If parsing failed, return error including ping's error and output
	if err!= nil {
		return 0, fmt.Errorf("ping command failed: %w (output: %q)", err, outputStr)
	}
	return 0, fmt.Errorf("failed to extract average latency from ping output: %q", outputStr)
}

