package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings a specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be at least 1")
	}
	if host == "" {
		return 0, errors.New("host must not be empty")
	}

	// Prepare ping command arguments based on operating system
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		// Linux, macOS, and other Unix-like systems
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute the ping command and capture combined stdout/stderr
	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w, output: %s", err, string(output))
	}

	outStr := string(output)

	// Select regex pattern based on OS to extract average latency
	var re *regexp.Regexp
	switch runtime.GOOS {
	case "windows":
		re = regexp.MustCompile(`Average\s*=\s*([\d.]+)\s*ms`)
	default:
		// Handle both mdev (Linux) and stddev (macOS) in output
		re = regexp.MustCompile(`rtt min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	}

	// Find the average latency value
	matches := re.FindStringSubmatch(outStr)
	if len(matches) < 2 {
		return 0, fmt.Errorf("unable to parse average latency from ping output: %s", outStr)
	}

	// Convert the captured string to float64
	avgLatency, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert latency value: %w", err)
	}

	return avgLatency, nil
}

func main() {
	// Check command line arguments
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	// Parse count argument to integer
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: ping count must be a valid integer, got '%s'\n", countStr)
		os.Exit(1)
	}

	// Measure latency
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	// Print result
	fmt.Printf("Average latency to %s (over %d pings): %.2f ms\n", host, count, avg)
}

