	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	// Build ping command arguments based on operating system
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count)}
	default:
		args = []string{"-c", strconv.Itoa(count)}
	}
	args = append(args, host)

	// Execute ping command, capture combined stdout/stderr
	cmd := exec.Command("ping", args...)
	output, _ := cmd.CombinedOutput() // Ignore command exit code first, prioritize parsing output

	// Regex to extract latency values (handles both = and < operators, e.g., time=12.3ms or time<1ms)
	latencyRegex := regexp.MustCompile(`time([=<])(\d+\.?\d*)`)
	matches := latencyRegex.FindAllStringSubmatch(string(output), -1)

	if len(matches) == 0 {
		return 0, fmt.Errorf("no valid latency measurements found, ping output: %s", string(output))
	}

	totalLatency := 0.0
	for _, match := range matches {
		operator := match[1]
		valueStr := match[2]
		latency, err := strconv.ParseFloat(valueStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse latency value %q: %w", valueStr, err)
		}

		// For "<" operator (e.g., <1ms), use half the value as a reasonable estimate
		if operator == "<" {
			latency = latency / 2
		}
		totalLatency += latency
	}

	return totalLatency / float64(len(matches)), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid ping count: %s, must be a positive integer\n", os.Args[2])
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avgLatency)
}

